INSERT INTO public.lecture_captions (lecture_session_id, start_sec, end_sec, text, language) VALUES
  ('e3333333-3333-4333-8333-333333333303'::uuid, 5, 13, '안녕하세요. 리얼 공감어 이명학입니다. 3월학평 해설 강의 시작할게요. 총평은네', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 13, 20, '당일날 라이브를 통해서 어려웠다. 미쳤다 이걸 풀려는 거냐? 야 이건', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 20, 29, '뭐 해 보자는 거지?라고 라고 충분히 말씀을 드렸어요. 아, 그래서 이번 해설 강의는 해설을 할', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 29, 35, '때 여러분하고 같이 마음을 좀 맞춰 가야 되는데 그러니까 보통 평소에 해설 강의라고 하면이 [콧방귀]', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 35, 41, '문제는 이랬고 실전에서는 일해야 하고 뭐 어떤 약간 전략은 어떻게 써야 되고 이런 방법론에 대한 이야기를 좀', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 41, 48, '많이 한다면 이번 시험은 어 일단 해석이 안 돼. 해석이', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 48, 55, '아마 이걸 내신 대비를 위해서이 지문을 많이 봐야 하는 학생들이라든지', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 55, 64, '아니면 N생 중에이 글을 봤을 때 해설지를 읽어도요. 이게 분명히 한 글인데이 너무', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 64, 69, '추상적이거나 비유적이거나 말을 비틀거나 말을 왔다 갔다 하거나이', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 69, 74, '표현이 무슨 말이지? 막 중간에 막 벡터 나오고 막', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 74, 81, '가단성이 있는 뭐 이런 말 자체가 문회력을 요구하는 글들이 많아서 어', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 81, 88, '글 자체를 좀 꼼꼼하게 읽는 방식으로 진행하겠습니다. 그니까 각 문제를 보면서 야 이거 3월에 이거 내도', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 88, 95, '돼? 아 이걸 어떻게 풀려는 거야? 이런 식의 태도를 가지면 어 처음부터까지 까야 돼. 예. 그래서', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 95, 100, '그럼 서로 피곤하니까 어 충분히 힘들었다라는 건 총평에서', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 100, 105, '말씀을 드렸기 때문에 해설가는', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 105, 112, '주요문항 주요 문항이라고 하자면 거의 다죠. 예. 얘네들을 한 문제씩', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 112, 120, '꼼꼼히 읽어 가면서이 글이 도대체 무슨 말이었는지 아 얘가이 문장이 결국이 글에서 무슨', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 120, 126, '말이었는지를 천천히 곱씹어 가면서 같이 이해해 보도록 하겠습니다.', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 126, 133, '아 사실 제가 문제를 꼼꼼하게 보면 느낀 건 문제 하나하나는요', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 133, 139, '굉장히 잘 만드셨어요. 문제 하나하나는 좋아. 그니까 글도 어 딱', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 139, 145, '읽으면서 기가 막힌데 어 출제진 중에 되게 놀라운 분인들이 계신가 봐요.', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 145, 150, '그니까 야 어디서 이런 걸 이렇게 찾았지 싶을만큼', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 150, 156, '어 좀 야 그 뇌를 훔치고 싶다 아라는 생각이 들만큼 좋은 글감', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 156, 161, '그리고 어 문제의 정답과 오답을 가르는 거에 있어서도 확실함. 그니까', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 161, 167, '문항 하나하나는 솔직히 잘 만들었어요.', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 167, 175, '어렵다며요? 어렵지. 어렵지만 잘 만들었어요. 고난도 문제라 생각했을 때 하나하나의 문제가 가지는 가치는', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 175, 182, '높다라고 생각합니다. 물론 모아놨기 때문에 미치는 거지. 이게 몇 개 들어가 있었으면 굉장히 아름다운', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 182, 187, '시험이 됐을 텐데 이걸 통으로 모아 놓으니까 거의 죽은 거죠.', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 187, 193, '근데 한 문항 한 문항은 좋다. 그래서 한 문항씩', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 193, 202, '아 천천히 가면서 보겠습니다. 자 함추금이 대입학네 문제 빈칸네', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 202, 210, '문제 순서 삽입 장문 독해 진행할게요. 21번', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 210, 215, '실전에서의 방법은 이랬어야 한다. 이런 것들은 최대한 지향하고 이글', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 215, 221, '전체가 무슨 말인지를 같이 읽어 볼게요. 처음에', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 221, 229, '뛰어난 음악가는 사실 혁신가가 될 수 있대요. 뭐 없이?', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 229, 237, '엄격히 말해서 발명가가 되는 거 없이. 예. 일단 여기서부터 어려운데', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 237, 242, '그니까 발명가가 되지 않아도 뭔가 새로울 수 있다이 말이야. 뭔가 뭔가를 만들어 내지 않아도 혁신적인', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 242, 248, '사람이 될 수 있다. 그러한 경우에 노수 어떤 사람이냐면', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 248, 254, '기대하는 사람 위대한 발견 소위 말하는 약간 비꾸는 거예요. 다운표를', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 254, 261, '찍은게 원래 의미를 비트는 거야. 위대하지 않은데 소위 말한 위대한 발견들 이걸 기대하는 사람은 실망할', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 261, 266, '것이다. 무슨 말이냐면 인벤터라는 건 뭔가를 만드는', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 266, 275, '사람이잖아요. 그러니까 뭔가를 만들어내는 거. 뭔가를 만들어낸다는 건 결국 위대한 발견들을 하는 거지.', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 275, 280, '그러니까이 연결이 되죠. 그러니까 위대한 발견이 있겠지라고', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 280, 288, '생각하는 사람들한테 실망이다. 왜? 이거 없이도 이노베이터가 될 수 있으니까.', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 288, 293, 'Let 해보자. There be no doubt. 무슨 말이야?', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 293, 301, '아웃. 의심이 없게 해 볼게. 의심이 없게 해보자. 의심이 없게 해.요 말에 의심이 없게 해보자.', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 301, 307, '그게 무슨 말이냐? 거기에 대한 부연 설명. 열정적인', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 307, 313, '필요해요. 필요. 뭐에 대한? 새로운 것에 대한 사람들이 새로운 걸 엄청', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 313, 320, '발래. 요거는 이해된 설명인데 내용을 위해서 일단 지나가 볼게.', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 320, 325, '열렬한 필요. 뭐에 대한? 참신함에 대한 그거는 수반한대요. 뭐를요?', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 325, 333, '생각을. 어떤 생각? 음악적인 활동은 어띵 어떤 하나의 사물이야.', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 333, 339, '물건이고요. 그러한 경우 안에서 음악은 no', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 339, 346, 'more than 된 이상은 아니니까 된 이상인가 없으니까 단지 뭐냐면 기술이야. 아 그냥 기술일 뿐이야.', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 346, 352, '그니까 음악을 기술로만 본다고. 음악을 기술로만 본다고. 다시 새로운', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 352, 358, '거를 너무 쳐다보면 음악을 뭘로 본다는 거야? 기술로만 본다는 거야. 음악은 그런게 아닌데 새로운 것만', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 358, 365, '너무 찾다 보면 음악을 뭘로 본다? 기술로만 본다. 그러면이', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 365, 372, '새로운 거에 대한 열렬한 요구가 뭐냐? 그다음 그만큼 특징적인 거예요.', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 372, 379, '뭐에? 점점 증가하는 점점 세지는', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 379, 384, '현대주의적 현대적 경매 이게 무슨 말이야? 야,', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 384, 390, '점점 커지는 현대적 경매. 이게 무슨 말이야?', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 390, 395, '경매가 뭐예요? 그 서로 막 경쟁하는 거잖아요. 그러니까 물건 갖다 놓고', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 395, 400, '어 내가 살래? 내가 살래? 내가 살 점점 이렇게 올라가는 거죠. 근데', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 400, 406, '현대주의적이야. 그러니까 이게 더 현대적이냐? 이게 더 현대적이냐?', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 406, 413, '이게 더 현대적이냐 하는 그런 경매를 하는 느낌인 거야. 그러니까 내 음악이 더 현대적이야. 내 음악이 더', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 413, 419, '새거야. 이게 왜 나온 거야? 참신함 때문에. 아, 그니까 참신함을 바란다는게 결국 이제 거의 경매', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 419, 427, '수준이라는 거야. 누가 더 현대적이냐라는 경매 수준까지 갔다는 거죠. 근데 그 참신함만 찾으면 뭐', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 427, 432, '한다 얘기예요? 음악을 기술만 본다고. 기술. 기술.', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 432, 439, '그리고 이게 just as랑 so죠.', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 439, 446, '딱 이거인 것처럼 이러하다야. 딱 이거인 것처럼. 딱 이거인 것처럼 쏘 그렇게', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 446, 452, '이러하다야 기술이라는 것이 결과물이에요. 결과물', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 452, 459, '기술은 결과물이지 뭐해? 무한정한 과정의 결과물이야. 완벽에', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 459, 465, '무슨 말이야? 기술을 A라는 기술을 만들었어. 또 완벽하게 하기 위해서', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 465, 472, '더 발전하고 더 발전하고 더 발전하고 더 계속 가는 거예요. 기술을 계속 발전하는 것처럼', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 472, 478, '거기에 대한 설명이에요. 각각의 자동차 또는', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 478, 485, '주방 가전 용품 쇼는요. 소개하죠. 뭐가 새로운지 그리고 뭐가 향상되는지', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 485, 492, '비교해서 작년과 그니까 계속 발전하는 거지. 자동차 어 작년보다 올해 이만큼', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 492, 499, '새로운 기술이 있어요. 가전 제품 새로운 기술이 있어요. 기술이라는 건 계속 새로운 거 새로운 거 새로운 거', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 499, 506, '추구하는 거죠. 그렇게 결코 끝나지 않는 과정이 법칙일 거다. 뭐에?', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 506, 514, '음악에. 그니까 음악을 기술로 보면 음악도 자꾸 뭐 하려고 한다는 거야? 작년보다 더 최신 기술, 더 최신', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 514, 521, '기술, 더 최신 기술이 된다이 말이죠. 더 멀리, 더 빠르게, 더 강력하게', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 521, 528, '이렇게 만든다고.', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 528, 534, '이러한 레이스가 뭐야? 원래 군비 경쟁이에요. 그러니까', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 534, 540, '무기 경쟁이니까 뭐 A라는 국가가 이러한 신무기를 만들면 B는 또 그거를 뭐 방어하는 걸 만들고 걔를', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 540, 546, '또 격파하는 걸 만들고이 계속 경쟁하는 거죠. 이런 경쟁 속에서', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 546, 553, '각각의 새로운 음악은요. 부서 깨 부서요. 뭐 그 선조 그보다', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 553, 559, '더 선배에 기록을 깨는 거야. 기록을 깨고 그 깨는 새로운 음악은', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 559, 567, '제공한다. 그 자신을 마지막 것 즉 최신의 것으로서 뭐 현대성이 내게', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 567, 573, '제일 최신이야이 말이지. 그리고 각각의 음악가는요. 강요에 그', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 573, 578, '선배들을 어디로 카테고리로 넣는 거예요. 보지 않고 유행에 좀', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 578, 585, '뒤떨어지고 구식이야. 이렇게 밀어넣으면서 주장하는 거지. 뭐 특허를 주장해요. 뭐에 대해서? 그', 'ko'),
