  ('e3333333-3333-4333-8333-333333333303'::uuid, 2368, 2374, '것 즉 다르다는 건 인정한다는 거잖아요. 그니까 반대입니다. 답은 2번. 이게 해설이라서 이렇게', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 2374, 2380, '풀렸지 실전에서는 매우 어려웠어요. 왜냐면이 뒤에가 이게 여기서 끊기는', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 2380, 2386, '건지 아니면 여기서 끊기서이 전환되는 건지', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 2386, 2391, '그리고이네 개의 보통 명사가 뭔지 이게 사실 어려웠습니다.', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 2391, 2398, '아 얘기 안 하기로 했는데 또 했네. 자 그 답은 2번을 뭐스 이런 걸', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 2398, 2403, '써야겠죠. 무시해 버린 거죠. 무시한', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 2403, 2408, '여기서 이제 반전 일어나는 거예. 줌인 이렇게 가까이 보라는 거죠. 얘', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 2408, 2415, '이제 멀리서 본 거예요. 앞에 내용은 문맥상. 그러니까 멀리서 똑 보면 잔디밭 보면', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 2415, 2421, '그냥 잔디밭이지. 거기 뭐 있는지 따져. 안 따지잖아. 이런 말이야. 근데 주민 인해서 봐라. 가까이 보면', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 2421, 2428, '그러면 너는 발견할 거예요. 개별성과 독특함을 발견한다고. 모든 곳에서', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 2428, 2435, '어떠한 두 개의 데이지도 또는 두 개의 클러버도 정확하게 똑같지 않다.', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 2435, 2443, '클러브가 뭐 좀 큰 놈도 있고 작은 놈도 있고 내입도 있고 세입도 있고 이럴 거 아니야. 다 다르다.', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 2443, 2450, '그러나 걔네들이 제시해 준대요.', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 2450, 2458, '이렇게 묶여야 돼요. 이걸 제시해 주는 거야. 걔네들은 카펫을 보여 주는 거야.', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 2458, 2465, '패턴화 된 거야. 균등하게 충분이. 누구한테는? 퀵 글랜스한테는. 퀵', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 2465, 2472, '글랜스에게는 뭐야? 빠르게 힐끔 보는 그런 눈에는 그냥 정용화된', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 2472, 2477, '그냥 카페야. 이렇게 보인다고. 다시. 그 얘네들은', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 2477, 2483, '다 똑같지 않거든. 그러나 걔네가 뭘 나타내 줘? 카페으로 보이는 거.', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 2483, 2491, '카페트. 패턴이 동일하게 충분히 돼 있는 거죠. 누구한테? 빠르게 보면이', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 2491, 2506, '말이지. 주민하지 않은 거. 이게 퀵글랜스라는 건 주민을 안 한 거겠죠.', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 2506, 2511, '4. 대부분의 실 일상적인 목적을 위해서 실용적인 일상적인 목적을', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 2511, 2517, '위해서는 그 차이들이 무시될 수 있대요. 일상적으로 무시해도 돼.', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 2517, 2523, '일상적인게 뭔데? 데이지 체인을 만들어. 데이지로 뭐 이렇게 무거 만드는데 이게 큰 거만 하고 작은', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 2523, 2529, '거만 이럴 필요 없다고. 그냥 기회하면 된다고. 무시할 수 있고요. 일광력을 해. 일광력. 일광령하는데', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 2529, 2534, '내가 이렇게 누웠는데 잔디 받아서 누웠는데 야 거기가 데이지로만 돼 있는지 뭐 클럽만 돼지 따질 필요', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 2534, 2541, '있어 그냥 무시해 된다고 뭐 그런 것들에 대해서 그러나 그렇지 않대요.', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 2541, 2548, '그러나 그렇지 않대. 누구한테? 어떤 땅을 관리하는 사람이야. 구장 관리인. 스포츠 스타디움에 뭐 축구장', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 2548, 2554, '관리인 이런 사람한테는 그렇지 않대. 거기서는 그 구성하는', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 2554, 2561, '그스 풀이나 그들의 생장 성장의 단계가 정말로 중요하거든. 뭐 그', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 2561, 2567, '우리 맨날 축구하면 뭐 잔디 구장 얘기하잖아. 잔디 그거 엄청 중요하잖아. 다 따져야 되잖아. 그', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 2567, 2572, '잔디 종도 따져야 되고 얼마나 컸는지 따져야.이 이 상태 중 한테는 무시될', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 2572, 2580, '수 없다는 거지. 그리고 누구에게 무한한 마음이에요. 무한한', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 2580, 2588, '메모리. 이건 뭐야? 한계가 없는 마음. 한계가 없는 메모리라는 건 어떤 약간 문맥상 신적', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 2588, 2594, '존재를 의미하는 거야. 그니까 어떤 신에게 있어서', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 2594, 2600, '그니까 마음이 이렇게 갇혀져 있지 않고 무한정한 존재고 영원히 기억하는 이런', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 2600, 2606, '존재에게는 각각의 꽃잎', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 2606, 2613, '그게 그 각각의 구분되는 삶의 히스토리를 가진 그 꽃잎은', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 2613, 2619, '함께 범주화될 필요가 없대요. 그 동료들과', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 2619, 2624, '그니까 신이 보기엔 저 데이지의 세 번째 꽃잎도 다 안다고 하나씩 다 볼', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 2624, 2631, '수 있다는 거죠. 각각은 가질 수 있다. 그 자체의 이름을 너 자신이', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 2631, 2637, '가지는 것처럼 그니까 너도 너 자신이 왜 나오는 거야? 처음에 고유명사잖아요. 당신의 이름 고유', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 2637, 2645, '명사잖아요. 그것처럼 사실 데이지라고 우리 다 데이지로 보는데 가까이 보면이 데이지는 이름이 있을 수 있고', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 2645, 2654, '신이 볼 땐 그 하나하나에 다 이름이 있을 수 있다는 얘기겠죠.', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 2654, 2661, '자 31번 예술인데 without commce', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 2661, 2669, '상업이 없어. 상업적인게 들어가지 않은 예술은 그냥 취미야.', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 2669, 2674, '상업성이 없으면 취미다. 이렇게 말했어.', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 2674, 2679, '이러한 단어들은요. 말해지거든. 이러한 말은 말해져.', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 2679, 2686, '많은 권위를 가지고 누구 졸업하려는 순수 예술 그 전공자한테 말하시거든.', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 2686, 2692, '야, 누가 그린 거 이게 팔리겠어? 이렇게 말하는 거지. 그거는', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 2692, 2700, 'are the kind 그러한 종류래요. 어떤 종류냐면 that 만드는 사람 예수를 만드는', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 2700, 2708, '사람이 무시할 수 없는 말이야. 예수라고 아 되나? 무시할 수 없는 말이에요. 우리는 걱정한다.이', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 2708, 2713, '생각에 대해서. 어떤 생각이에요? 만약 우리가 어떤 [콧방귀] 상업에', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 2713, 2718, '관여하지 않으면 우리는 프로페셔널 전문가가 아닌 거', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 2718, 2724, '아니야. 이렇게 생각하는 거죠. 그 만약 우리가 프로페셔널하지 않다면 전문가가', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 2724, 2729, '아니라면 우리는 심지어 우리 자신을 예술가라고 부를 수 있나? 상업성이 들어가지', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 2729, 2739, '않으면 나는 예술가일까? 이렇게 생각한다고. 어떤 형태의 예술 이건간에 그 본질상', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 2739, 2745, 'not 할 수도 없고요. 슈 not 해서는 안 돼. 수량화 돼서는 안 돼. 그니까 지금 말을 여기서 하면', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 2745, 2752, '좀 전환이 되죠. 야, 상업화 되지 않으면 예술이 아니야. 그 걱정하는 거. 나 이거', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 2752, 2757, '내가 예술가 맞아. 근데이 사람의 의도는 이거죠. 예술이라는 건 원래', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 2757, 2764, '수량화 돼서는 안 돼. 그러나 작가들이', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 2764, 2770, '측정해요. 페이지를 그 단어를 내가 몇 페이지 썼지? 몇 단어 썼지. 그 그리고 비주얼 아티스트들은 측정하는', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 2770, 2777, '거죠. 캔버스를 세는 거예요. 완성된 모드 뭐떤 노력에서 보이려고 좀', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 2777, 2785, '생산적으로 보이려고 내가 팔게 몇 개지? 내가 비주얼 아티스트니까 내가 몇 점 만들었지? 이걸 샌다고요.', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 2785, 2793, '아마도 정당화고 그 충동을 창작하려는 무슨 말이에요? 원래 예술은', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 2793, 2800, '수량 될 수 없는 거거든. 근데 상업성이 있어야 되니까 라이터나 비주얼 아티스트가 내가 지금 몇 개나', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 2800, 2807, '쓰고 그렸는지를 세고 있다고 생각이에요. 만드는 거야. 창작하는', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 2807, 2815, '거죠. [콧방귀] 예술 그 자체를 위해서 예술을 예술로 창작하는 건 보여져. 그래서 뭘로 보여져?', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 2815, 2822, '[한숨] 희망 없이 그냥 로맨틱한 낭만적인 거네. 그냥 그리고 거의', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 2822, 2828, '방어를 못 해 주겠어. 예술을 예술로 싸는 거 굶어 죽어 봐야지 이렇게', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 2828, 2834, '이렇게 되는 거죠.이 예술 맞나? 이렇게 된다는 거죠. 그까이 사람은 지금', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 2834, 2840, '어 원래 생각은 예술은 예술이어야지라는 생각 갖고 있는 사람이야. 근데 우리 저런 말 들으면 흔들린다. 이런 말', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 2840, 2847, '하고 있는 거야.', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 2847, 2853, '물론 한 사람이 예수를 할 수 있어요.', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 2853, 2861, '근데 더 좋지. 돈 벌려고 하면 더 좋은 거야.', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 2861, 2866, '왜냐면 그게 유일한 표시거든. 성공의', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 2866, 2872, '그니까 그래. 물론 예술를 하는데 물론 예수할 수 있지. 근데 돈을', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 2872, 2880, '위해서 하면 더 좋잖아. 왜 돈까지 벌면 성공한 거니까 그러나', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 2880, 2888, '여기서 그 교수의 선언 교수 나왔어요? 교수 교수 안', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 2888, 2896, '나왔는데 그 교수의 선호는 거의', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 2896, 2901, '나이든 그 말만 하는 사람이야. 근데 그 사람이 타이틀 갖고 있어요. 그냥', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 2901, 2907, '생각 없이 반복하는 거야. 문화적 규범이나 기대를 근데 그게', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 2907, 2912, '사실 그에게 이름표를 붙여 주는 거지. 뭐 성공적이라 무슨 말이야 [웃음]', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 2912, 2919, '이게? 얘는 안 나와 있는데 문맥상 알 수 있는 거 뭐야? 첫 문장에 이거죠.', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 2919, 2926, '예술은 상어 없는 예술은 취미야.이 다운 편에 있는 거. 이거를이', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 2926, 2932, '디클레이션 볼 수 있죠. 사실 좀 심했죠. 왜냐면 이게 앞에서 그 교수이 나왔겠지만', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 2932, 2939, '어쩔 수 없이 알 수 있는 저밖에 없어요. 그러니까 즉 야 상업적인게 없으면 예술이 아니야라고 말하는 그', 'ko'),
