  ('e3333333-3333-4333-8333-333333333303'::uuid, 2950, 2957, '빚는 거야. 저 말은 그냥 올드 토커 아니야. 그냥 [콧방귀] 수다적인 노인의 말 아니야.', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 2957, 2964, '근데 그 노인이 타이틀이 있어요. 타이틀이 노인이 그 교수니까 타이틀이 있겠지.', 'ko'),
