  ('e3333333-3333-4333-8333-333333333303'::uuid, 4166, 4171, '그거를 이렇게 쓴 거예요. 방향과 양이 두', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 4171, 4179, '개가 더해져 있다고. 방향 하면 오타가 발음도 어려워. 방향이 뭐야? 방향. 방향과', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 4179, 4187, '양 크기가 같이 있다고요. 어쨌든 갑시다.', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 4187, 4192, '영어 시간입니다. 네. 봅시다.', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 4192, 4198, '생각해 보대. 생각해 보자. 그 전체를 너의 인터락션에 너의 상황 관계에', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 4198, 4205, '어디서 행동적인 그리고 상호 행동적인 데이터가', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 4205, 4214, '기록되고 보존되는 곳에서 모든 거 그러한 흔적의 모든 것은', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 4214, 4219, '나타낸대요. 일종의 리소스 자원을 나타낸다', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 4219, 4226, '걔는 축적되죠. 오랜 역사에 걸쳐서 너의 기록된', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 4226, 4233, '행동과 선택에 그리고 만들어져요. 흔적으로부터 남겨진 모든', 'ko'),
