  ('e3333333-3333-4333-8333-333333333303'::uuid, 4413, 4418, '잘 봐. 아, 걔가 정보의 벡터 형태가었을 때요. 근데', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 4418, 4424, '그게 뭔지 모를까 봐 설명. 그게 너의 상황과 가치를 많은 특징과', 'ko'),
