  ('e3333333-3333-4333-8333-333333333303'::uuid, 4464, 4471, '뭐 처음부터 끝까지 여기 위치를 알려준다. 위치를 안 된다는 얘기가 도배돼 있었기 때문에 문제 자체가', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 4471, 4476, '어렵지는 않았을 겁니다.', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 4476, 4482, '36번부터는 다음 강에이어서 할게요. 네. 다음 강에서 봅시다.', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 4482, 4491, '다시 접니다. 여기까지 했고 36번부터 갑시다. 항상 방법은 전과동 주어진', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 4491, 4498, '문자 읽고 A B C의 앞부분을 보면서 연결되는지 단절되는지를', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 4498, 4505, '시그널과 스테이터스로 확인한 후 가장 확실한 거부터 연결 단절한다.가 볼게요.이', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 4505, 4511, '사람이 주장해요. 한 가지 이익인데 도덕적 고려를 하는', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 4511, 4519, '것, 고려 상황을 갖는 것의 이익은 어떤 개념적 레퍼토리에서 우리의', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 4519, 4529, '뭐냐면 걔네가 역할을 할 수 있대요. 대화를 스토퍼 막아 주는 거예요.', 'ko'),
