  ('e3333333-3333-4333-8333-333333333303'::uuid, 4535, 4540, '대화를 막아준 뭔 소리야 몰라. 그 설명', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 4540, 4546, '나오지. 그들의 가치는', 'ko'),
