  ('e3333333-3333-4333-8333-333333333303'::uuid, 4552, 4559, '생각을 안 하게 만들어 준다고. 생각을 심사 숙구하는 걸 클로즈 끝내 준다고.', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 4559, 4566, '우리는 합리적 존재예요. 항상 요구할 수 있죠. 정당화를 요구할 수', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 4566, 4574, '있어요. 이것이 특징인데 우리한테 좋은 역할을 해 왔죠. 많은', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 4574, 4581, '상황에서. 사실 여기까지가 전체의 내용이고요.', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 4581, 4588, '여기서부터 이제 이야기가 구체가 되는 거야. 그니까 인간은 항상 그게 맞아. 그게 맞아. 그게 맞아? 이걸', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 4588, 4593, '계속 물어보는 존재라는 거예.', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 4593, 4603, '이것은 잠재적으로 어 그렇게 많은 문제가 된대요. 우리 자신의 어떤 사적인 사유에 있어서만큼', 'ko'),
