  ('e3333333-3333-4333-8333-333333333303'::uuid, 4614, 4621, '모르겠어. 물론 여기 디스가 있지만이 디스가 뭔지 모르겠어요.', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 4621, 4629, '그건 도덕적으로 잘못된 거야.이 말은 이러한 방식으로 작동할 것처럼', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 4629, 4638, '보인다. 이러한 방식 작동에 뭔지 모르겠어.', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 4638, 4645, '문제는 뭐냐? 완벽한게 좋은 답을 받자마자 우리는', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 4645, 4650, '항상 어 센서블리하게 응답해요. 오케이 오케이', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 4650, 4657, '알겠어. 근데 그게 그걸 정당하는게 뭔데? 이렇게 또 물어보는 거죠.', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 4657, 4662, '모르겠어요. 셋다 물음표야. 그래서 3점이야.', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 4662, 4670, '그럼 자연스럽게 뭐가 떠올라야 돼? 스테이터스', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 4670, 4675, '소재 연결성이죠.', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 4675, 4682, '뭐 어떻게 한다? 오케 나눠. A의 앞과 뒤를 나누고', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 4682, 4691, 'B의 앞과 뒤를 나누고 C의 앞과 뒤를 나누려고 했는데 없어. 이런 그럼 A와 B의 앞뒤를', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 4691, 4699, '읽어서 소재가 연결되 상 소재 연결되는 거. A 볼게요. 이건 잠재적으로 그렇게', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 4699, 4704, '많은 문제가 된대요. 우리 자신의 사적 사유에 있어서 생각에 있어서', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 4704, 4711, '우리의 공적인 사람 사이의 사유 만큼이라 여긴 문제에 되네. 문제.', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 4711, 4717, '그 문제였어요.이 사람은 제한하죠.', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 4717, 4724, '유용하대요. 뭐를? 어, 생각을 만들어내는 거를 다치게', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 4724, 4730, '하는 거이 뭐래? 찍소리 못 하게 하는 말이래. 억제기 이게 유용할 수', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 4730, 4739, '있대요. 이게 뭔데? 모를까 봐 또 알려줍니다. 아이템인데 일단 도입되면 막아줘.', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 4739, 4745, '어떤 더 나가는 생각을 막아 줘요. 어, 그 트랙에 있어서. 아, 이건', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 4745, 4750, '뭐야? 일종에 해결책이죠.', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 4750, 4758, '그럼 나눴을 때 A 앞에는 문제에 대한 얘기가 있을 거고 A의 뒤에는 해결에 대한 얘기가', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 4758, 4764, '있었겠지. 이게 뭐야? 소재 연결성.', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 4764, 4770, '걔는 도덕적으로 잘못된 거야라는게 보일 수 있어요. 나타날 수 있어.', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 4770, 4778, '이러한 방식으로 작동을 한대요. 일단 그 주장이 받아들여지면 then 그러면', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 4778, 4783, '필요가 없어요. 공간도 없어요. 더 나아간 정당한 걸 찾을 정당화를 찾을', 'ko'),
  ('e3333333-3333-4333-8333-333333333303'::uuid, 4783, 4792, '필요가 없어. 그 행동은 행해져서 안 되고요. 그게 되게 유혹적이고', 'ko'),
